-- Step 1: Extend name column
ALTER TABLE categories ALTER COLUMN name TYPE VARCHAR\(200\);

-- Step 2: Add new columns as nullable first
ALTER TABLE categories ADD COLUMN IF NOT EXISTS path VARCHAR\(1000\);
ALTER TABLE categories ADD COLUMN IF NOT EXISTS depth INT DEFAULT 0;
ALTER TABLE categories ADD COLUMN IF NOT EXISTS node_type VARCHAR\(20\) DEFAULT 'SEEDED';
ALTER TABLE categories ADD COLUMN IF NOT EXISTS active BOOLEAN DEFAULT TRUE;
ALTER TABLE categories ADD COLUMN IF NOT EXISTS demande_count BIGINT DEFAULT 0;
ALTER TABLE categories ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT NOW\(\);

-- Step 3: Backfill path for root nodes
UPDATE categories SET path = id::TEXT WHERE parent_id IS NULL AND path IS NULL;

-- Step 4: Backfill path for depth-1 nodes
UPDATE categories c
SET    path  = p.path || '.' || c.id::TEXT,
       depth = 1
FROM   categories p
WHERE  c.parent_id = p.id
  AND  c.path IS NULL;

-- Step 5: Backfill any remaining nulls \(safety\)
UPDATE categories SET path = id::TEXT WHERE path IS NULL;

-- Step 6: Set NOT NULL constraints
ALTER TABLE categories ALTER COLUMN path SET NOT NULL;
ALTER TABLE categories ALTER COLUMN depth SET NOT NULL;
ALTER TABLE categories ALTER COLUMN node_type SET NOT NULL;
ALTER TABLE categories ALTER COLUMN active SET NOT NULL;
ALTER TABLE categories ALTER COLUMN demande_count SET NOT NULL;

-- Step 7: Indexes
CREATE INDEX IF NOT EXISTS idx_category_path         ON categories\(path\);
CREATE INDEX IF NOT EXISTS idx_category_path_pattern ON categories\(path text_pattern_ops\);
CREATE INDEX IF NOT EXISTS idx_category_active       ON categories\(active\);
CREATE INDEX IF NOT EXISTS idx_category_node_type    ON categories\(node_type\);

-- Step 8: category_attributes table
CREATE TABLE IF NOT EXISTS category_attributes \(
    id           BIGSERIAL PRIMARY KEY,
    category_id  BIGINT       NOT NULL REFERENCES categories\(id\) ON DELETE CASCADE,
    key          VARCHAR\(100\) NOT NULL,
    label        VARCHAR\(200\) NOT NULL,
    type         VARCHAR\(20\)  NOT NULL DEFAULT 'TEXT',
    required     BOOLEAN      NOT NULL DEFAULT FALSE,
    inherited    BOOLEAN      NOT NULL DEFAULT FALSE,
    display_order INT         NOT NULL DEFAULT 0,
    options      TEXT
\);
CREATE INDEX IF NOT EXISTS idx_category_attributes_category_id ON category_attributes\(category_id\);
